using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Breaking change 1: Default discriminator property renamed from
            // "Discriminator" to "$type" in EF Core 9. Keep the old name so
            // existing documents are still matched.
            b.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: The JSON "id" value no longer includes the
            // discriminator prefix (was "Blog|1", now just "1"). Opt back in
            // so existing documents with "Blog|<key>" ids are found.
            b.HasDiscriminatorInJsonId();

            // Breaking change 3: HasIndex now throws for the Cosmos provider.
            // Cosmos uses its own indexing policy; remove the EF-level index.
            // (HasIndex call removed)
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

